function readPath(source, path) {
  return path.split(".").reduce((current, key) => (current && current[key] !== undefined ? current[key] : undefined), source);
}

export function getDictionary(locale) {
  return dictionaries[supportedLocales.includes(locale) ? locale : DEFAULT_LOCALE];
}

export function translate(locale, key, params = {}) {
  const dictionary = getDictionary(locale);
  const fallback = dictionaries[DEFAULT_LOCALE];
  const template = readPath(dictionary, key) ?? readPath(fallback, key) ?? key;

  if (typeof template !== "string") {
    return template;
  }

  return template.replace(/\{(\w+)\}/g, (_, token) => {
    const value = params[token];
    return value === undefined || value === null ? "" : String(value);
  });
}
